CREATE TABLE IF NOT EXISTS drivers (
    driver_id INTEGER PRIMARY KEY,
    name VARCHAR(100),
    hire_date DATE,
    tier VARCHAR(20),
    status VARCHAR(20),
    region VARCHAR(20),
    license_class CHAR(1),
    training_batch VARCHAR(20)
);

CREATE TABLE IF NOT EXISTS vehicle_assignments (
    assignment_id INTEGER PRIMARY KEY,
    driver_id INTEGER REFERENCES drivers(driver_id),
    vehicle_type VARCHAR(50),
    vehicle_id VARCHAR(20),
    current_mileage INTEGER,
    last_service_date DATE,
    avg_fuel_efficiency DECIMAL(4,1)
);

CREATE TABLE IF NOT EXISTS zones (
    zone_id INTEGER PRIMARY KEY,
    zone_name VARCHAR(100),
    base_difficulty DECIMAL(3,1),
    region VARCHAR(20),
    active BOOLEAN DEFAULT TRUE,
    max_daily_routes INTEGER DEFAULT 50
);

CREATE TABLE IF NOT EXISTS zone_managers (
    zone_id INTEGER REFERENCES zones(zone_id),
    manager_name VARCHAR(100),
    start_date DATE,
    end_date DATE
);

CREATE TABLE IF NOT EXISTS weather_events (
    event_id INTEGER PRIMARY KEY,
    event_date DATE,
    region VARCHAR(20),
    condition VARCHAR(30),
    severity VARCHAR(20),
    duration_hours INTEGER
);

CREATE TABLE IF NOT EXISTS training_completions (
    completion_id INTEGER PRIMARY KEY,
    driver_id INTEGER REFERENCES drivers(driver_id),
    training_type VARCHAR(50),
    completion_date DATE,
    score INTEGER
);

CREATE TABLE IF NOT EXISTS shifts (
    shift_id INTEGER PRIMARY KEY,
    driver_id INTEGER REFERENCES drivers(driver_id),
    shift_date DATE,
    zone_id INTEGER REFERENCES zones(zone_id),
    start_time TIME,
    end_time TIME,
    deliveries_completed INTEGER,
    route_target INTEGER,
    break_minutes INTEGER,
    overtime_flag CHAR(1),
    route_miles DECIMAL(6,1)
);

CREATE TABLE IF NOT EXISTS driver_zone_history (
    driver_id INTEGER REFERENCES drivers(driver_id),
    zone_id INTEGER REFERENCES zones(zone_id),
    first_worked_date DATE,
    total_days_in_zone INTEGER,
    last_worked_date DATE,
    PRIMARY KEY (driver_id, zone_id)
);

CREATE TABLE IF NOT EXISTS feedback (
    feedback_id INTEGER PRIMARY KEY,
    driver_id INTEGER REFERENCES drivers(driver_id),
    zone_id INTEGER REFERENCES zones(zone_id),
    rating DECIMAL(2,1),
    feedback_date DATE,
    comment TEXT
);

CREATE TABLE IF NOT EXISTS fuel_costs (
    date DATE,
    region VARCHAR(20),
    price_per_gallon DECIMAL(4,2),
    weekly_average DECIMAL(4,2),
    PRIMARY KEY (date, region)
);

CREATE TABLE IF NOT EXISTS route_incidents (
    incident_id INTEGER PRIMARY KEY,
    shift_id INTEGER REFERENCES shifts(shift_id),
    incident_type VARCHAR(50),
    delay_minutes INTEGER,
    resolved BOOLEAN
);

CREATE TABLE IF NOT EXISTS bonus_payments (
    payment_id INTEGER PRIMARY KEY,
    driver_id INTEGER REFERENCES drivers(driver_id),
    shift_id INTEGER REFERENCES shifts(shift_id),
    shift_date DATE,
    base_performance_index DECIMAL(10,2),
    zone_difficulty_factor DECIMAL(6,3),
    tier_multiplier DECIMAL(4,2),
    final_score DECIMAL(10,2),
    bonus_amount DECIMAL(10,2),
    calculated_at TIMESTAMP,
    paid_at TIMESTAMP,
    batch_id VARCHAR(30),
    status VARCHAR(20),
    UNIQUE (driver_id, shift_date)
);

CREATE TABLE IF NOT EXISTS calc_audit_log (
    log_id INTEGER PRIMARY KEY,
    payment_id INTEGER REFERENCES bonus_payments(payment_id),
    log_date DATE,
    event_type VARCHAR(30),
    source_system VARCHAR(30),
    details TEXT
);













